import React, { useState, useEffect } from 'react';

// ── VARIANTE 1 : Guerrière Accueil (épée levée, cape dorée) ──
function GuerriereAccueil() {
  return (
    <div style={{ width: '70px', height: '70px', position: 'relative', flexShrink: 0 }}>
      <style>{`
        @keyframes swordGlow { 0%,100%{filter:drop-shadow(0 0 4px #ffd700);} 50%{filter:drop-shadow(0 0 12px #ffd700) drop-shadow(0 0 20px #ffaa00);} }
        @keyframes capeWave { 0%,100%{transform:skewX(0deg);} 50%{transform:skewX(4deg);} }
        @keyframes eyeGlow { 0%,100%{opacity:0.8;} 50%{opacity:1; filter:drop-shadow(0 0 3px #00ff88);} }
      `}</style>
      <svg viewBox="0 0 70 70" width="70" height="70" xmlns="http://www.w3.org/2000/svg">
        {/* Fond cercle */}
        <circle cx="35" cy="35" r="34" fill="#0a0f1e" stroke="#ffd700" strokeWidth="1.5"/>
        {/* Cape */}
        <g style={{animation:'capeWave 3s ease-in-out infinite'}}>
          <ellipse cx="35" cy="52" rx="18" ry="14" fill="#1a0a00" opacity="0.9"/>
          <path d="M17 52 Q10 65 20 68 Q35 72 50 68 Q60 65 53 52" fill="#2a0a00" opacity="0.8"/>
          <path d="M20 52 Q15 60 22 65 Q35 68 48 65 Q55 60 50 52" fill="#ffd70022"/>
        </g>
        {/* Corps */}
        <rect x="27" y="36" width="16" height="18" rx="4" fill="#1a0a0a" stroke="#ffd700" strokeWidth="0.8"/>
        {/* Armure torse */}
        <path d="M27 38 Q35 34 43 38 L43 48 Q35 50 27 48Z" fill="#2a1500" stroke="#ffd700" strokeWidth="0.5"/>
        <line x1="35" y1="36" x2="35" y2="50" stroke="#ffd70066" strokeWidth="0.5"/>
        {/* Cou */}
        <rect x="32" y="28" width="6" height="10" rx="2" fill="#3d1a0a"/>
        {/* Tête */}
        <ellipse cx="35" cy="22" rx="11" ry="12" fill="#3d1a0a"/>
        {/* Cheveux naturels longs */}
        <path d="M24 18 Q20 12 22 6 Q28 2 35 4 Q42 2 48 6 Q50 12 46 18" fill="#0a0a0a" stroke="#111" strokeWidth="0.3"/>
        <path d="M24 18 Q18 28 20 40 Q22 46 24 48" fill="#111" stroke="#0a0a0a" strokeWidth="3" strokeLinecap="round"/>
        <path d="M46 18 Q52 28 50 40 Q48 46 46 48" fill="#111" stroke="#0a0a0a" strokeWidth="3" strokeLinecap="round"/>
        {/* Cheveux avant */}
        <path d="M25 16 Q28 10 35 12 Q42 10 45 16" fill="#0d0d0d"/>
        {/* Visage */}
        <ellipse cx="35" cy="24" rx="9" ry="10" fill="#5c2d0a"/>
        {/* Yeux */}
        <g style={{animation:'eyeGlow 2s ease-in-out infinite'}}>
          <ellipse cx="31" cy="22" rx="2.5" ry="2" fill="#001a00"/>
          <ellipse cx="39" cy="22" rx="2.5" ry="2" fill="#001a00"/>
          <circle cx="31" cy="22" r="1.2" fill="#00ff88"/>
          <circle cx="39" cy="22" r="1.2" fill="#00ff88"/>
          <circle cx="31.5" cy="21.5" r="0.4" fill="#fff"/>
          <circle cx="39.5" cy="21.5" r="0.4" fill="#fff"/>
        </g>
        {/* Sourcils */}
        <path d="M28.5 19.5 Q31 18.5 33.5 19.5" stroke="#1a0a0a" strokeWidth="1" fill="none" strokeLinecap="round"/>
        <path d="M36.5 19.5 Q39 18.5 41.5 19.5" stroke="#1a0a0a" strokeWidth="1" fill="none" strokeLinecap="round"/>
        {/* Bouche */}
        <path d="M32 27.5 Q35 29 38 27.5" stroke="#ff6644" strokeWidth="1" fill="none" strokeLinecap="round"/>
        {/* Bras gauche */}
        <rect x="18" y="37" width="9" height="5" rx="2" fill="#1a0a0a" stroke="#ffd700" strokeWidth="0.5"/>
        {/* Bras droit avec épée levée */}
        <rect x="43" y="30" width="5" height="9" rx="2" fill="#1a0a0a" stroke="#ffd700" strokeWidth="0.5"/>
        {/* ÉPÉE */}
        <g style={{animation:'swordGlow 2s ease-in-out infinite'}}>
          <rect x="47" y="4" width="2.5" height="28" rx="1" fill="url(#swordGrad)"/>
          <rect x="44" y="26" width="8" height="2.5" rx="1" fill="#ffd700"/>
          <rect x="46.5" y="30" width="3" height="5" rx="1" fill="#aa7700"/>
        </g>
        <defs>
          <linearGradient id="swordGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#ffffff"/>
            <stop offset="40%" stopColor="#aaddff"/>
            <stop offset="100%" stopColor="#ffd700"/>
          </linearGradient>
        </defs>
        {/* Ornement front */}
        <circle cx="35" cy="15" r="2" fill="#ffd700" opacity="0.8"/>
      </svg>
    </div>
  );
}

// ── VARIANTE 2 : Guerrière Services (armure cyber, bouclier) ──
function GuerriereServices() {
  return (
    <div style={{ width: '70px', height: '70px', position: 'relative', flexShrink: 0 }}>
      <style>{`
        @keyframes shieldPulse { 0%,100%{stroke-opacity:0.6;} 50%{stroke-opacity:1; filter:drop-shadow(0 0 8px #00ff88);} }
        @keyframes armorGlow { 0%,100%{opacity:0.7;} 50%{opacity:1;} }
      `}</style>
      <svg viewBox="0 0 70 70" width="70" height="70" xmlns="http://www.w3.org/2000/svg">
        <circle cx="35" cy="35" r="34" fill="#0a0f1e" stroke="#00aa00" strokeWidth="1.5"/>
        {/* Corps armure */}
        <rect x="25" y="36" width="20" height="20" rx="4" fill="#0a1a0a" stroke="#00aa00" strokeWidth="0.8"/>
        {/* Plaques armure */}
        <g style={{animation:'armorGlow 2.5s ease-in-out infinite'}}>
          <path d="M25 38 Q35 34 45 38 L45 50 Q35 53 25 50Z" fill="#0d2a0d" stroke="#00ff88" strokeWidth="0.5"/>
          <path d="M29 40 L41 40" stroke="#00ff8844" strokeWidth="1"/>
          <path d="M27 44 L43 44" stroke="#00ff8844" strokeWidth="1"/>
          <path d="M29 48 L41 48" stroke="#00ff8844" strokeWidth="1"/>
        </g>
        {/* Cou */}
        <rect x="32" y="29" width="6" height="9" rx="2" fill="#3d1a0a"/>
        {/* Tête */}
        <ellipse cx="35" cy="22" rx="11" ry="12" fill="#3d1a0a"/>
        {/* Cheveux */}
        <path d="M24 16 Q22 8 28 5 Q35 3 42 5 Q48 8 46 16" fill="#0a0a0a"/>
