// ── COMPOSANT PRINCIPAL ──
function Mascotte({ messages, position = 'left', variante = 'accueil' }) {
  const [texteAffiche, setTexteAffiche] = useState('');
  const [indexMessage, setIndexMessage] = useState(0);
  const [indexChar, setIndexChar] = useState(0);
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    if (indexChar < messages[indexMessage].length) {
      const timer = setTimeout(() => {
        setTexteAffiche(prev => prev + messages[indexMessage][indexChar]);
        setIndexChar(prev => prev + 1);
      }, 40);
      return () => clearTimeout(timer);
    } else {
      const timer = setTimeout(() => {
        setVisible(false);
        setTimeout(() => {
          setTexteAffiche('');
          setIndexChar(0);
          setIndexMessage(prev => (prev + 1) % messages.length);
          setVisible(true);
        }, 500);
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [indexChar, indexMessage, messages]);

  const isLeft = position === 'left';

  const PersonnageMap = {
    accueil:  <GuerriereAccueil />,
    services: <GuerriereServices />,
    apropos:  <GuerriereApropos />,
  };

  const bordureColor = {
    accueil:  '#ffd700',
    services: '#00aa00',
    apropos:  '#8833ff',
  };

  return (
    <div style={{
      display: 'flex', alignItems: 'flex-end', gap: '12px',
      flexDirection: isLeft ? 'row' : 'row-reverse',
      opacity: visible ? 1 : 0, transition: 'opacity 0.4s ease',
      margin: '20px 0'
    }}>
      {/* PERSONNAGE */}
      <div style={{
        flexShrink: 0, borderRadius: '50%',
        border: `3px solid ${bordureColor[variante]}`,
        boxShadow: `0 0 20px ${bordureColor[variante]}44`,
        animation: 'mascFloat 3s ease-in-out infinite',
        overflow: 'hidden'
      }}>
        {PersonnageMap[variante] || <GuerriereAccueil />}
      </div>

      {/* BULLE */}
      <div style={{
        background: 'rgba(0,10,30,0.95)',
        border: `1px solid ${bordureColor[variante]}`,
        borderRadius: isLeft ? '20px 20px 20px 0' : '20px 20px 0 20px',
        padding: '14px 18px', maxWidth: '260px',
        boxShadow: `0 0 20px ${bordureColor[variante]}22`
      }}>
        <p style={{
          color: '#c8d8e8', fontFamily: "'Rajdhani', sans-serif",
          fontSize: '14px', lineHeight: 1.6, margin: 0, minHeight: '20px'
        }}>
          {texteAffiche}
          <span style={{
            display: 'inline-block', width: '2px', height: '14px',
            background: bordureColor[variante], marginLeft: '2px',
            animation: 'mascBlink 0.7s infinite', verticalAlign: 'middle'
          }} />
        </p>
      </div>

      <style>{`
        @keyframes mascFloat { 0%, 100% { transform: translateY(0px); } 50% { transform: translateY(-8px); } }
        @keyframes mascBlink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
      `}</style>
    </div>
  );
}

export default Mascotte;
